function playBass(t,fr,dur){if(!audioCtx)return;var o=audioCtx.createOscillator(),g=audioCtx.createGain(),lp=audioCtx.createBiquadFilter();o.type="sawtooth";o.frequency.setValueAtTime(fr,t);lp.type="lowpass";lp.frequency.value=400;g.gain.setValueAtTime(0.5,t);g.gain.setValueAtTime(0.5,t+dur*0.7);g.gain.exponentialRampToValueAtTime(0.01,t+dur);o.connect(lp);lp.connect(g);g.connect(bassGain);o.start(t);o.stop(t+dur);}
function playLead(t,fr,dur){if(!audioCtx)return;var o=audioCtx.createOscillator(),g=audioCtx.createGain(),lp=audioCtx.createBiquadFilter();o.type="square";o.frequency.setValueAtTime(fr,t);lp.type="lowpass";lp.frequency.value=1500;g.gain.setValueAtTime(0.15,t);g.gain.exponentialRampToValueAtTime(0.01,t+dur);o.connect(lp);lp.connect(g);g.connect(leadGain);o.start(t);o.stop(t+dur);}
