function saveHighScore(idx,sc){var key='s'+idx;if(!highScores[key]||sc>highScores[key]){highScores[key]=sc;try{localStorage.setItem('gtg_scores',JSON.stringify(highScores));}catch(e){}}}function getHighScore(idx){return highScores['s'+idx]||0;}function getGrade(pct){if(pct>=95)return'S';if(pct>=85)return'A';if(pct>=70)return'B';if(pct>=50)return'C';return'D';}function getGradeColor(g){if(g==='S')return'#FFD700';if(g==='A')return'#00F5D4';if(g==='B')return'#FEE440';if(g==='C')return'#FF006E';return'#888';}function spawnParticles(x,y,col,cnt){for(var i=0;i<cnt;i++){particles.push({x:x,y:y,vx:(Math.random()-0.5)*4,vy:-Math.random()*3-1,life:30+Math.random()*20,col:col,sz:2+Math.random()*3});}}
function startSong(idx){initAudio();resumeAudio();var _bpms=[140,135,150,160,120,170,180,128,128,128,130,200,120,202,128,150,220];startMusic(_bpms[idx]||140,idx);songIdx=idx;var s=songs[idx];notes=s.notes.slice();activeNotes=[];score=0;combo=0;maxCombo=0;perfect=0;good=0;miss=0;frame=0;songTime=0;bpm=s.bpm;spb=60/s.bpm;streak=0;bestStreak=0;paused=false;particles=[];state='play';}
function tryHit(lane){if(paused)return;var best=-1,bestD=999;for(var i=0;i<activeNotes.length;i++){var n=activeNotes[i];if(n.l===lane&&!n.hit){var d=Math.abs(n.y-HIT_Y);if(d<bestD){bestD=d;best=i;}}}if(best>=0&&bestD<40){activeNotes[best].hit=true;if(bestD<15){perfect++;score+=100+combo*10;hitFx.push({x:lane*LANE_W+LANE_W/2,y:HIT_Y,t:20,c:'#00F5D4',txt:'PERFECT',sc:1.5});onNoteHit();spawnParticles(lane*LANE_W+LANE_W/2,HIT_Y,COLORS[lane],12);comboGlow=15;}else{good++;score+=50+combo*5;hitFx.push({x:lane*LANE_W+LANE_W/2,y:HIT_Y,t:20,c:'#FEE440',txt:'GOOD',sc:1.2});onNoteHit();spawnParticles(lane*LANE_W+LANE_W/2,HIT_Y,COLORS[lane],6);comboGlow=10;}combo++;streak++;if(combo>maxCombo)maxCombo=combo;if(streak>bestStreak)bestStreak=streak;}}
function drawTitle(){ctx.fillStyle='#0a0a1a';ctx.fillRect(0,0,W,H);for(var i=0;i<40;i++){var sx=(i*137+frame)%W,sy=(i*97+frame*0.3)%H;var br=0.3+0.3*Math.sin(frame*0.02+i);ctx.fillStyle='rgba(255,255,255,'+br+')';ctx.fillRect(sx,sy,1,1);}ctx.save();ctx.shadowColor='#FF006E';ctx.shadowBlur=15+5*Math.sin(frame*0.05);ctx.fillStyle='#FF006E';ctx.font='bold 28px sans-serif';ctx.textAlign='center';ctx.fillText('GHOST TAP',W/2,80);ctx.shadowColor='#00F5D4';ctx.fillStyle='#00F5D4';ctx.font='bold 24px sans-serif';ctx.fillText('GROOVE',W/2,110);ctx.restore();ctx.fillStyle='#FEE440';ctx.font='bold 10px sans-serif';ctx.textAlign='center';ctx.fillText('HARD MODE',W/2,135);var a=0.5+0.5*Math.sin(frame*0.06);ctx.fillStyle='rgba(255,255,255,'+a+')';ctx.font='12px sans-serif';ctx.fillText('TAP TO START',W/2,200);ctx.fillStyle='#666';ctx.font='8px sans-serif';ctx.fillText('v2.0 - QoL Edition',W/2,270);frame++;}
function drawSelect(){ctx.fillStyle='#0a0a1a';ctx.fillRect(0,0,W,H);ctx.fillStyle='#FEE440';ctx.font='bold 14px sans-serif';ctx.textAlign='center';ctx.fillText('SELECT SONG',W/2,20);var startY=35;var scrollOff=Math.max(0,selSong-2)*38;for(var i=0;i<songs.length;i++){var y=startY+i*38-scrollOff;if(y<25||y>H-40)continue;var s=songs[i];var sel=(i===selSong);if(sel){ctx.fillStyle='rgba(255,255,255,0.1)';ctx.fillRect(5,y-8,W-10,34);ctx.strokeStyle=COLORS[i%3];ctx.lineWidth=2;ctx.strokeRect(5,y-8,W-10,34);ctx.lineWidth=1;}var hs=getHighScore(i);ctx.fillStyle=sel?'#fff':'#aaa';ctx.font=sel?'bold 11px sans-serif':'10px sans-serif';ctx.textAlign='left';ctx.fillText(s.name,12,y+5);var diff=s.difficulty||'normal';var dc=diff==='easy'?'#00F5D4':diff==='hard'?'#FF006E':diff==='expert'?'#FF006E':diff==='master'?'#FF0000':'#FEE440';ctx.fillStyle=dc;ctx.font='8px sans-serif';ctx.fillText(diff.toUpperCase(),12,y+17);ctx.fillStyle='#888';ctx.textAlign='right';ctx.fillText(s.bpm+'bpm',W-12,y+5);if(hs>0){ctx.fillStyle='#FFD700';ctx.fillText('HI:'+hs,W-12,y+17);}}ctx.fillStyle='#666';ctx.font='9px sans-serif';ctx.textAlign='center';ctx.fillText('Scroll:Nav | Side:Play',W/2,H-8);frame++;}
function drawGame(){ctx.save();ctx.fillStyle='#0a0a1a';ctx.fillRect(0,0,W,H);for(var i=1;i<LANES;i++){ctx.strokeStyle='rgba(255,255,255,0.08)';ctx.beginPath();ctx.moveTo(i*LANE_W,0);ctx.lineTo(i*LANE_W,H);ctx.stroke();}var glA=0.15+0.05*Math.sin(frame*0.1);ctx.fillStyle='rgba(255,255,255,'+glA+')';ctx.fillRect(0,HIT_Y-2,W,4);for(var i=0;i<LANES;i++){var cx=i*LANE_W+LANE_W/2;ctx.beginPath();ctx.arc(cx,HIT_Y,8+2*Math.sin(frame*0.08+i),0,Math.PI*2);ctx.strokeStyle=COLORS[i];ctx.globalAlpha=0.4;ctx.stroke();ctx.globalAlpha=1.0;}for(var i=0;i<activeNotes.length;i++){var n=activeNotes[i];if(n.hit)continue;var nx=n.l*LANE_W+LANE_W/2;var dh=Math.abs(n.y-HIT_Y);if(dh<60){var gw=1.0-dh/60;ctx.shadowColor=COLORS[n.l];ctx.shadowBlur=gw*15;}ctx.fillStyle=COLORS[n.l];ctx.beginPath();ctx.arc(nx,n.y,10,0,Math.PI*2);ctx.fill();ctx.fillStyle='rgba(255,255,255,0.3)';ctx.beginPath();ctx.arc(nx-3,n.y-3,4,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;}for(var i=hitFx.length-1;i>=0;i--){var f=hitFx[i];var a=f.t/20;ctx.globalAlpha=a;ctx.fillStyle=f.c;ctx.font='bold '+(10*(f.sc||1))+'px sans-serif';ctx.textAlign='center';ctx.fillText(f.txt,f.x,f.y-25+(20-f.t)*1.5);ctx.globalAlpha=1.0;f.t--;if(f.t<=0)hitFx.splice(i,1);}for(var i=particles.length-1;i>=0;i--){var p=particles[i];p.x+=p.vx;p.y+=p.vy;p.vy+=0.1;p.life--;var a=p.life/50;ctx.globalAlpha=a;ctx.fillStyle=p.col;ctx.fillRect(p.x-p.sz/2,p.y-p.sz/2,p.sz,p.sz);ctx.globalAlpha=1.0;if(p.life<=0)particles.splice(i,1);}ctx.fillStyle='#fff';ctx.font='bold 10px sans-serif';ctx.textAlign='left';ctx.fillText('Score:'+score,5,12);ctx.textAlign='right';if(combo>=5){var cg=comboGlow>0?Math.min(1,comboGlow/10):0;ctx.fillStyle='rgba(255,'+Math.floor(215+40*cg)+',0,1)';ctx.font='bold 12px sans-serif';ctx.fillText(combo+'x',W-5,12);}else{ctx.fillStyle='#fff';ctx.font='10px sans-serif';ctx.fillText('Combo:'+combo,W-5,12);}if(streak>=10){ctx.fillStyle='#FF006E';ctx.font='bold 8px sans-serif';ctx.textAlign='center';ctx.fillText('STREAK:'+streak,W/2,12);}if(comboGlow>0)comboGlow--;var prog=songTime/(notes.length>0?notes[notes.length-1].t+2:1);ctx.fillStyle='rgba(255,255,255,0.2)';ctx.fillRect(0,H-3,W,3);ctx.fillStyle='#00F5D4';ctx.fillRect(0,H-3,W*Math.min(1,prog),3);if(paused){ctx.fillStyle='rgba(0,0,0,0.7)';ctx.fillRect(0,0,W,H);ctx.fillStyle='#fff';ctx.font='bold 20px sans-serif';ctx.textAlign='center';ctx.fillText('PAUSED',W/2,H/2-10);ctx.font='10px sans-serif';ctx.fillText('Tap to resume',W/2,H/2+15);}ctx.restore();frame++;}
function drawResults(){ctx.fillStyle='#0a0a2e';ctx.fillRect(0,0,W,H);ctx.fillStyle='#FF006E';ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.fillText('RESULTS',W/2,25);var sn=songs[songIdx].name;ctx.fillStyle='#aaa';ctx.font='10px sans-serif';ctx.fillText(sn,W/2,42);var tot=perfect+good+miss;var pct=tot>0?Math.round((perfect+good)/tot*100):0;var gr=getGrade(pct);ctx.save();ctx.shadowColor=getGradeColor(gr);ctx.shadowBlur=20;ctx.fillStyle=getGradeColor(gr);ctx.font='bold 40px sans-serif';ctx.fillText(gr,W/2,90);ctx.restore();ctx.fillStyle='#fff';ctx.font='12px sans-serif';ctx.fillText('Score: '+score,W/2,115);ctx.fillStyle='#00F5D4';ctx.fillText('Perfect: '+perfect,W/2,135);ctx.fillStyle='#FEE440';ctx.fillText('Good: '+good,W/2,150);ctx.fillStyle='#FF006E';ctx.fillText('Miss: '+miss,W/2,165);ctx.fillStyle='#fff';ctx.fillText('Max Combo: '+maxCombo,W/2,185);ctx.fillText('Best Streak: '+bestStreak,W/2,200);var hs=getHighScore(songIdx);var isNew=score>hs;if(isNew&&score>0){ctx.fillStyle='#FFD700';ctx.font='bold 10px sans-serif';ctx.fillText('NEW HIGH SCORE!',W/2,218);}saveHighScore(songIdx,score);ctx.fillStyle='#FEE440';ctx.font='bold 14px sans-serif';ctx.fillText(pct+'%',W/2,238);var a=0.5+0.5*Math.sin(frame*0.08);ctx.fillStyle='rgba(255,255,255,'+a+')';ctx.font='10px sans-serif';ctx.fillText('TAP TO CONTINUE',W/2,262);frame++;}
function gameLoop(){if(state==='title'){drawTitle();}else if(state==='select'){drawSelect();}else if(state==='play'){if(!paused){songTime+=1/60;for(var i=0;i<activeNotes.length;i++){var n=activeNotes[i];if(!n.hit){n.y=HIT_Y-(n.t-songTime)*NOTE_SPEED*60;if(n.y>H+30&&!n.hit){n.hit=true;miss++;onNoteMiss();combo=0;streak=0;hitFx.push({x:n.l*LANE_W+LANE_W/2,y:HIT_Y,t:10,c:'rgba(255,0,0,0.5)',txt:'MISS',sc:0.8});}}}while(notes.length>0&&notes[0].t<songTime+2){activeNotes.push({t:notes[0].t,l:notes[0].l,y:-20,hit:false});notes.shift();}var allDone=true;for(var i=0;i<activeNotes.length;i++){if(!activeNotes[i].hit){allDone=false;break;}}if(allDone&&notes.length===0){stopMusic();state='results';}}drawGame();}else if(state==='results'){drawResults();}requestAnimationFrame(gameLoop);}
c.addEventListener('click',function(){initAudio();resumeAudio();},{once:true});c.addEventListener('click',function(e){if(state==='title'){state='select';return;}if(state==='select'){startSong(selSong);return;}if(state==='results'){state='select';return;}if(state==='play'&&paused){paused=false;return;}var x=e.offsetX||e.layerX||0;var lane=Math.floor(x/LANE_W);if(lane>=0&&lane<LANES)tryHit(lane);});c.addEventListener('touchstart',function(e){e.preventDefault();if(state==='title'){state='select';return;}if(state==='select'){startSong(selSong);return;}if(state==='results'){state='select';return;}if(state==='play'&&paused){paused=false;return;}var t=e.touches[0];var r=c.getBoundingClientRect();var x=t.clientX-r.left;var lane=Math.floor(x/LANE_W);if(lane>=0&&lane<LANES)tryHit(lane);},{passive:false});
window.addEventListener('scrollUp',function(){if(state==='play')tryHit(0);else if(state==='select'){selSong=(selSong-1+songs.length)%songs.length;}else if(state==='title')state='select';else if(state==='results')state='select';});window.addEventListener('scrollDown',function(){if(state==='play')tryHit(2);else if(state==='select'){selSong=(selSong+1)%songs.length;}else if(state==='title')state='select';else if(state==='results')state='select';});window.addEventListener('sideClick',function(){if(state==='play'){if(paused){paused=false;}else{tryHit(1);}}else if(state==='select')startSong(selSong);else if(state==='title')state='select';else if(state==='results')state='select';});window.addEventListener('longPressStart',function(){if(state==='play')paused=true;});
document.addEventListener('keydown',function(e){if(e.key==='a'||e.key==='ArrowLeft'){if(state==='play')tryHit(0);else if(state==='select'){selSong=(selSong-1+songs.length)%songs.length;}}if(e.key==='s'||e.key==='ArrowDown'){if(state==='play')tryHit(1);else if(state==='select')startSong(selSong);else if(state==='title')state='select';else if(state==='results')state='select';}if(e.key==='d'||e.key==='ArrowRight'){if(state==='play')tryHit(2);else if(state==='select'){selSong=(selSong+1)%songs.length;}}if(e.key==='ArrowUp'&&state==='select'){selSong=(selSong-1+songs.length)%songs.length;}if(e.key===' '||e.key==='Enter'){if(state==='select')startSong(selSong);else if(state==='title')state='select';else if(state==='results')state='select';else if(state==='play')paused=!paused;}if(e.key==='Escape'){if(state==='play')paused=!paused;else if(state==='select')state='title';}});
gameLoop();
